code = """import json
import os

# Load CHI filenames from Mongo result variable
chi_records = var_call_rthQSsjqCMWXjDsUtbmJYYCu

# Build a set of CHI paper titles by stripping the .txt extension
chi_titles = set()
for rec in chi_records:
    fn = rec.get('filename', '')
    if fn.endswith('.txt'):
        title = fn[:-4]
    else:
        title = fn
    chi_titles.add(title)

# Load the 2020 citations from the JSON file path provided
citations_file = var_call_6xXbFEIE0mfjVyIJRq0f6M95
with open(citations_file, 'r', encoding='utf-8') as f:
    citations = json.load(f)

# Sum citation counts for records whose title is in CHI titles
total_citations = 0
for row in citations:
    title = row.get('title')
    if title in chi_titles:
        cc = row.get('citation_count')
        try:
            cc_int = int(cc)
        except Exception:
            # handle None or non-numeric
            try:
                cc_int = int(float(cc))
            except Exception:
                cc_int = 0
        total_citations += cc_int

result = json.dumps({"total_citations_for_CHI_in_2020": total_citations})
print("__RESULT__:")
print(result)"""

